import{_ as o,a as e,b as a,c as d,d as n}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as r}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as l,o as i,c as s,a2 as p}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Other/ocr.md","filePath":"cs-CZ/Other/ocr.md","lastUpdated":1781962217000}'),c={name:"cs-CZ/Other/ocr.md"};function u(v,t,h,k,b,y){return i(),s("div",null,[...t[0]||(t[0]=[p('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR získává text z obrázků, skenů a snímků dokumentů.</p><p>Po rozpoznání můžete výsledek zkopírovat, exportovat jako <code>Markdown</code>, <code>PDF</code> nebo <code>Word</code>, případně stáhnout více formátů společně jako balíček.</p><h2 id="co-ocr-umi" tabindex="-1">Co OCR umí <a class="header-anchor" href="#co-ocr-umi" aria-label="Permalink to &quot;Co OCR umí&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funkce</th><th>Popis</th></tr></thead><tbody><tr><td>Rozpoznávání textu v obrázku</td><td>Získává text z obrázků, screenshotů a skenů.</td></tr><tr><td>Rozpoznávání rozložení dokumentu</td><td>Vhodnější pro tabulky, vzorce, razítka a smíšená textově-obrazová rozložení.</td></tr><tr><td>Více služeb</td><td>Podporuje Baidu PaddleOCR, Microsoft Azure Vision a Google Vision.</td></tr><tr><td>Kopírování výsledků</td><td>Po zpracování lze zkopírovat rozpoznaný text.</td></tr><tr><td>Export souborů</td><td>Exportuje <code>Markdown</code>, <code>PDF</code> a <code>Word</code>.</td></tr><tr><td>Hromadné balení</td><td>Po rozpoznání více souborů stáhne výsledky jako balíček.</td></tr></tbody></table><h2 id="nejdriv-nastavte-ocr-sluzby" tabindex="-1">Nejdřív nastavte OCR služby <a class="header-anchor" href="#nejdriv-nastavte-ocr-sluzby" aria-label="Permalink to &quot;Nejdřív nastavte OCR služby&quot;">​</a></h2><p>Otevřete:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+o+'" alt="IP geolokace a OCR" loading="lazy"></p><p>Vyplňte přihlašovací údaje služeb, které chcete použít:</p><table tabindex="0"><thead><tr><th>Služba</th><th>Co zadat</th><th>Nejvhodnější pro</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Doporučená první volba. Dobré pro dokumenty, obrázky, tabulky a smíšená rozložení.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> a <code>Azure Vision API Key</code></td><td>Užitečné, pokud už používáte cloudové služby Microsoft.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> slouží jen pro dotaz na kvótu.</td><td>Užitečné, pokud používáte Google Cloud.</td></tr></tbody></table><p>Po vyplnění údajů uložte.</p><p>Pro první test stačí nastavit jednu službu. Není nutné mít všechny tři.</p><h2 id="nastaveni-google-vision" tabindex="-1">Nastavení Google Vision <a class="header-anchor" href="#nastaveni-google-vision" aria-label="Permalink to &quot;Nastavení Google Vision&quot;">​</a></h2><p>Nastavení Google má dvě části:</p><table tabindex="0"><thead><tr><th>Cíl</th><th>Požadavek</th></tr></thead><tbody><tr><td>Použít OCR</td><td>Zapnout <code>Cloud Vision API</code>, potom vytvořit <code>API Key</code>.</td></tr><tr><td>Dotaz na využití</td><td>Vytvořit service account, přidat roli <code>Monitoring Viewer</code>, potom stáhnout service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+r+'" alt="Google API key a service account" loading="lazy"></p><h3 id="pouziti-google-pro-ocr" tabindex="-1">Použití Google pro OCR <a class="header-anchor" href="#pouziti-google-pro-ocr" aria-label="Permalink to &quot;Použití Google pro OCR&quot;">​</a></h3><ol><li>Otevřete Google Cloud Console.</li><li>Přejděte do <code>APIs &amp; Services</code>.</li><li>Otevřete <code>Library</code>, vyhledejte <code>Cloud Vision API</code> a zapněte ji.</li><li>Vraťte se do <code>Credentials</code>.</li><li>Vytvořte <code>API Key</code>.</li><li>Otevřete API Key a zkopírujte ho.</li><li>Vložte ho do <code>Google Vision API Key</code> v ImgBed.</li><li>Uložte.</li></ol><p>Potom můžete v dialogu OCR zvolit Google Vision.</p><h3 id="dotaz-na-vyuziti-google" tabindex="-1">Dotaz na využití Google <a class="header-anchor" href="#dotaz-na-vyuziti-google" aria-label="Permalink to &quot;Dotaz na využití Google&quot;">​</a></h3><p>Dotaz na kvótu není nutný pro samotné rozpoznávání.</p><p>Pouze přibližně ukáže, kolik volání Google Vision bylo použito za posledních 30 dní.</p><ol><li>V Google Cloud Console otevřete <code>IAM &amp; Admin</code>.</li><li>Otevřete <code>Service Accounts</code>.</li><li>Vytvořte service account, například <code>vision-monitor</code>.</li><li>Přidejte mu roli <code>Monitoring Viewer</code>.</li><li>Otevřete detail service account a vytvořte klíč.</li><li>Vyberte <code>JSON</code>.</li><li>Stáhněte vygenerovaný JSON soubor.</li><li>Vraťte se do ImgBed a importujte ho jako service account <code>JSON</code> (volitelné).</li><li>Po úspěšném importu klikněte na dotaz na kvótu.</li></ol><p>Po importu ImgBed ukáže název projektu, ke kterému service account patří. Při dotazu na využití čte Google monitoring data a ukáže počet volání za tento měsíc.</p><p>Stručně:</p><table tabindex="0"><thead><tr><th>Položka</th><th>Účel</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Provádí OCR rozpoznávání.</td></tr><tr><td>Service account <code>JSON</code></td><td>Dotazuje, kolik volání Google Vision bylo použito.</td></tr><tr><td>Role <code>Monitoring Viewer</code></td><td>Umožní service account číst data využití.</td></tr></tbody></table><h2 id="ziskani-baidu-paddleocr-tokenu" tabindex="-1">Získání Baidu PaddleOCR tokenu <a class="header-anchor" href="#ziskani-baidu-paddleocr-tokenu" aria-label="Permalink to &quot;Získání Baidu PaddleOCR tokenu&quot;">​</a></h2><p>Baidu PaddleOCR vyžaduje access token.</p><p><img src="'+e+'" alt="Získání PaddleOCR tokenu" loading="lazy"></p><p>Na stránce Baidu PaddleOCR otevřete okno volání <code>API</code>, klikněte na získání tokenu a zkopírujte ho.</p><p>Vraťte se do ImgBed, vložte ho do <code>PaddleOCR Token</code> a uložte.</p><h2 id="spusteni-rozpoznavani" tabindex="-1">Spuštění rozpoznávání <a class="header-anchor" href="#spusteni-rozpoznavani" aria-label="Permalink to &quot;Spuštění rozpoznávání&quot;">​</a></h2><p>Ve Správě souborů vyberte obrázek nebo snímek dokumentu a klikněte na <code>OCR</code>.</p><p><img src="'+a+'" alt="OCR rozpoznávání" loading="lazy"></p><p>V dialogu vyberte službu a model rozpoznávání.</p><p>Běžné modely PaddleOCR:</p><table tabindex="0"><thead><tr><th>Model</th><th>Nejvhodnější pro</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Doporučený výchozí model. Dobré pro dokumenty, tabulky, vzorce, razítka a smíšená rozložení.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Jednoduché obrázky, běžný text a lehké rozpoznávání.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Vícejazyčné, složité obrázky a obsah podobný grafům.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Složitější dokumentové stránky a obnovu rozložení.</td></tr></tbody></table><p>Pokud si nejste jistí, začněte s <code>PP-StructureV3</code>.</p><h2 id="pokrocile-volby" tabindex="-1">Pokročilé volby <a class="header-anchor" href="#pokrocile-volby" aria-label="Permalink to &quot;Pokročilé volby&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Volba</th><th>Popis</th></tr></thead><tbody><tr><td>Korekce orientace</td><td>Použijte, když je obrázek otočený nebo nakloněný.</td></tr><tr><td>Narovnání dokumentu</td><td>Použijte pro fotografované dokumenty se zakřivením nebo perspektivou.</td></tr><tr><td>Detekce rozložení</td><td>Použijte, když chcete zachovat nadpisy, odstavce, tabulky a strukturu obrázku.</td></tr><tr><td>Rozpoznávání grafů</td><td>Použijte, když obrázek obsahuje grafy nebo složité struktury.</td></tr><tr><td>Vylepšit <code>Markdown</code></td><td>Zpřehlední exportovaný Markdown.</td></tr></tbody></table><p>U běžných screenshotů nechte voleb minimum. U skenů dokumentů zapněte víc dokumentových voleb.</p><h2 id="zobrazeni-vysledku" tabindex="-1">Zobrazení výsledků <a class="header-anchor" href="#zobrazeni-vysledku" aria-label="Permalink to &quot;Zobrazení výsledků&quot;">​</a></h2><p>Po dokončení rozpoznávání dialog ukáže výsledek.</p><p>Můžete ho zkopírovat přímo nebo vybrat exportní formáty.</p><p><img src="'+d+'" alt="Rozpoznávání PDF" loading="lazy"></p><p>U dokumentových stránek může exportovaný <code>PDF</code> zachovat vzhled stránky a zároveň udržet text vyhledatelný. Hodí se to pro archivaci skenů a pozdější hledání obsahu.</p><h2 id="vyber-exportniho-formatu" tabindex="-1">Výběr exportního formátu <a class="header-anchor" href="#vyber-exportniho-formatu" aria-label="Permalink to &quot;Výběr exportního formátu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Formát</th><th>Nejvhodnější pro</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Poznámky, dokumentační systémy a pozdější úpravy.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Zachování vzhledu stránky a výsledků skenu.</td></tr><tr><td><code>Word (.docx)</code></td><td>Další úpravy rozložení, textu a předání ostatním.</td></tr><tr><td>Export všeho</td><td>Uloží více formátů a původní obrázek, vhodné pro důležité archivy.</td></tr></tbody></table><p>Pokud potřebujete jen text, exportujte Markdown.</p><p>Pokud potřebujete vzhled stránky, použijte PDF nebo Word.</p><h2 id="vystup-word" tabindex="-1">Výstup Word <a class="header-anchor" href="#vystup-word" aria-label="Permalink to &quot;Výstup Word&quot;">​</a></h2><p>Exportované dokumenty Word lze otevřít a upravovat v kancelářském softwaru.</p><p><img src="'+n+`" alt="Výsledek Word" loading="lazy"></p><p>Některé dokumenty ve výstupu Word obsahují rozpoznané obrázky, nadpisy a odstavce.</p><p>Kvalita závisí na čitelnosti originálu, volbě modelu a složitosti dokumentu.</p><h2 id="nejlepsi-typy-souboru-pro-ocr" tabindex="-1">Nejlepší typy souborů pro OCR <a class="header-anchor" href="#nejlepsi-typy-souboru-pro-ocr" aria-label="Permalink to &quot;Nejlepší typy souborů pro OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Typ souboru</th><th>Doporučení</th></tr></thead><tbody><tr><td>Čitelné screenshoty</td><td>Rozpoznávejte přímo.</td></tr><tr><td>Skeny</td><td>Preferujte <code>PP-StructureV3</code>.</td></tr><tr><td>Fotografované dokumenty</td><td>Zapněte korekci orientace a narovnání dokumentu.</td></tr><tr><td>Tabulky, vzorce, razítka</td><td>Preferujte strukturované modely.</td></tr><tr><td>Jednoduché krátké textové obrázky</td><td><code>PP-OCRv5</code> obvykle stačí.</td></tr></tbody></table><p>Čitelnější obrázky s rovnějším textem obvykle dávají lepší výsledky.</p><h2 id="bezne-pripady" tabindex="-1">Běžné případy <a class="header-anchor" href="#bezne-pripady" aria-label="Permalink to &quot;Běžné případy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Případ</th><th>Význam</th></tr></thead><tbody><tr><td>Rozpoznávání selže</td><td>Zkontrolujte, že token nebo key služby jsou uložené.</td></tr><tr><td>Rozpoznávání je pomalé</td><td>Složité dokumenty a velké obrázky trvají déle.</td></tr><tr><td>Tabulka je neúplná</td><td>Zkuste strukturovaný model.</td></tr><tr><td>Text obsahuje chyby</td><td>Rozmazání, odlesky a naklonění zvyšují chybovost. Zkuste čitelnější obrázek.</td></tr><tr><td>Výstup Word obsahuje mnoho obrázků</td><td>Strukturované modely mohou zachovat některé rozpoznané obrázky. Je to normální.</td></tr></tbody></table><h3 id="dotaz-na-kvotu-google-selze" tabindex="-1">Dotaz na kvótu Google selže <a class="header-anchor" href="#dotaz-na-kvotu-google-selze" aria-label="Permalink to &quot;Dotaz na kvótu Google selže&quot;">​</a></h3><p>Zkontrolujte:</p><ol><li>Service account <code>JSON</code> byl importován.</li><li>Service account má roli <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> je v projektu zapnutá.</li></ol><p>Pokud potřebujete jen OCR a ne dotaz na využití, můžete service account JSON ignorovat a vyplnit jen <code>Google Vision API Key</code>.</p><h2 id="rychly-postup" tabindex="-1">Rychlý postup <a class="header-anchor" href="#rychly-postup" aria-label="Permalink to &quot;Rychlý postup&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otevřete System Settings</span></span>
<span class="line"><span>-&gt; Otevřete Other Settings</span></span>
<span class="line"><span>-&gt; Vyplňte údaje OCR služby</span></span>
<span class="line"><span>-&gt; Uložte</span></span>
<span class="line"><span>-&gt; Vraťte se do Správy souborů</span></span>
<span class="line"><span>-&gt; Vyberte soubor a klikněte OCR</span></span>
<span class="line"><span>-&gt; Vyberte model</span></span>
<span class="line"><span>-&gt; Počkejte na rozpoznání</span></span>
<span class="line"><span>-&gt; Zkopírujte výsledky nebo exportujte Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const j=l(c,[["render",u]]);export{g as __pageData,j as default};
